<template>
  <div class="startup-container">
    <div class="background-animation"></div>
    <el-card class="startup-card">
      <template #header>
        <div class="card-header">
          <h2>{{ brandConfig.ename }} <span class="version">v{{ version }}</span></h2>
        </div>
      </template>
      
      <div class="startup-content">
        <div class="instructions">
          <h3>启动向导</h3>
          <ol>
            <li>请确保已登录至少1个微信号</li>          
            <!-- <li>打开微信窗口，让窗口可见</li> -->
            <li class="important-tip">
              <span class="important-icon">⚠️</span>
              <strong>确保微信窗口可见，不要最小化或关闭</strong>
            </li>
            <li>点击启动应用后，不要操作鼠标</li>
            <li>以上知晓后，点击下方按钮启动应用~</li>
          </ol>
        </div>

        <div class="startup-progress" v-if="initializing">
          <el-progress 
            :percentage="progress" 
            :status="progressStatus"
            :stroke-width="8"
            :show-text="false"
          />
          <p class="progress-text">{{ progressText }}</p>
      </div>
      
      <div class="startup-actions">
          <!-- <el-button 
            type="primary" 
            :loading="initializing"
            @click="handleStartup"
            class="start-button"
          >
            {{ initializing ? '正在启动...' : '启动应用' }}
          </el-button> -->
          <!-- 添加多微信启动按钮 -->
          <el-button 
            type="warning" 
            :loading="initializing"
            @click="handleMultiStartup"
            class="start-button multi-start-button"
            style="margin-top: 16px;"
          >
            {{ initializing ? '正在启动...' : '启动应用' }}
          </el-button>

          <!-- 代理商入口按钮 -->
          <!-- <el-button v-if="showAgentEntry" type="success" class="agent-entry-btn" @click="goAgentLogin" style="margin-top: 16px;">
            代理商入口
          </el-button> -->

          <!-- 添加免责声明 -->
          <div class="disclaimer">
            <p>免责声明</p>
            <ul>
              <li>本软件仅供日常交流使用，严禁用于非法用途</li>
              <li>请遵守相关法律法规，违规使用造成的后果由使用者承担</li>
            </ul>
          </div>
        </div>
      </div>
    </el-card>

    <el-dialog v-model="showEnvConfigDialog" title="设备环境异常~" width="460px" align-center class="env-dialog">
      <template #header>
        <div class="dialog-header warning">
          <el-icon class="warning-icon"><WarningFilled /></el-icon>
          <span class="dialog-title">设备环境异常~</span>
        </div>
      </template>
      <div class="dialog-content">
        <p class="dialog-subtitle">您使用的是4.1版本微信，需要进行设备环境配置。点击下方按钮，会自动执行以下配置：</p>
        <div class="steps-panel">
          <div class="step-item" :class="{ done: autoConfigSteps[1] === 'done' }">
            <span class="step-index">1</span>
            <span class="step-text">退出当前微信程序<span v-if="autoConfigSteps[1] === 'done'">（√）</span></span>
          </div>
          <div class="step-item" :class="{ done: autoConfigSteps[2] === 'done' }">
            <span class="step-index">2</span>
            <span class="step-text">配置电脑环境变量<span v-if="autoConfigSteps[2] === 'done'">（√）</span></span>
          </div>
          <div class="step-item" :class="{ done: autoConfigSteps[3] === 'done' }">
            <span class="step-index">3</span>
            <span class="step-text">启动“讲述人”模式并运行 10 秒<span v-if="autoConfigSteps[3] === 'done'">（√）</span></span>
          </div>
          <div class="step-item" :class="{ done: autoConfigSteps[4] === 'done' }">
            <span class="step-index">4</span>
            <span class="step-text">重新启动微信程序<span v-if="autoConfigSteps[4] === 'done'">（√）</span></span>
          </div>
        </div>
      </div>
      <template #footer>
        <el-button
          class="dialog-primary"
          type="primary"
          :loading="autoConfigRunning"
          :disabled="autoConfigRunning"
          @click="startAutoConfig"
        >
          {{ autoConfigRunning ? '正在自动配置' : '开始自动配置' }}
        </el-button>
      </template>
    </el-dialog>

    <el-dialog v-model="showConfigCompleteDialog" title="自动配置完成！" width="380px" align-center class="complete-dialog">
      <div class="dialog-content">
        <p class="dialog-summary">已完成配置（先不要关闭讲述人模式）</p>
        <p class="dialog-subtitle">请登录微信后，点击下方按钮启动应用</p>
      </div>
      <template #footer>
        <el-button
          class="dialog-primary"
          type="primary"
          :loading="initializing"
          :disabled="initializing"
          @click="launchAppAfterConfig"
        >
          {{ initializing ? '正在启动' : '启动应用' }}
        </el-button>
      </template>
    </el-dialog>
  </div>
</template>
  
<script setup lang="ts">
import { ref, inject, onMounted, onUnmounted } from 'vue'
import { useRouter, useRoute } from 'vue-router'
import { ElMessage } from 'element-plus'
import { WarningFilled } from '@element-plus/icons-vue'
import { initializeMultipleWechat, autoConfigWechat41, stopNarrator } from '@/api/init'
import { version } from '../../package.json'
import type { BrandConfig } from '@/config/brand'
import { checkAgentExists } from '@/api/agent'
const brandConfig = inject<BrandConfig>('brandConfig', {
  channel_id:'channel_000001',
  name: 'Yoko微信机器人',
  ename: 'YokoAIbot',
  logo: '/assets/logo.png',
  contact: '473726474@qq.com'
})
const router = useRouter()
const route = useRoute()
const initializing = ref(false)
const progress = ref(0)
const progressStatus = ref<'success' | 'exception'>('success')
const progressText = ref('')
const showEnvConfigDialog = ref(false)
const showConfigCompleteDialog = ref(false)
const agentName = ref<string | null>(null)
const autoConfigRunning = ref(false)
const autoConfigSteps = ref<Record<number, 'pending' | 'start' | 'done'>>({1:'pending',2:'pending',3:'pending',4:'pending'})

const updateProgress = (value: number, text: string) => {
  progress.value = value
  progressText.value = text
}
// const handler = (e: any) => {
//   console.log('auto-config-progress', e.detail)
//   const { step, status } = e.detail || {}
//   const s = Number(step)
//   if ([1,2,3,4].includes(s) && status) {
//     autoConfigSteps.value = { ...autoConfigSteps.value, [s]: status }
//   }
// }
onMounted(async () => {
  const agent = route.query.agent as string | undefined
  if (agent) {
    agentName.value = agent
    const isAgent = await checkAgentExists(agent)
    if (isAgent) {
      goAgentLogin()
    }
  }
  // window.addEventListener('auto-config-progress', handler as any)

})
  // onUnmounted(() => {
  //   window.removeEventListener('auto-config-progress', handler as any)
  // })

const handleMultiStartup = async () => {
  if (initializing.value) return
  
  try {
    initializing.value = true
    progressStatus.value = 'success'
    
    updateProgress(20, '正在检查微信状态...')
    // initializing.value = false
    // showEnvConfigDialog.value = true
    // return
    // 初始化所有微信实例
    const result = await initializeMultipleWechat()
    
    if (result.success) {
      updateProgress(60, '正在初始化微信实例...')

      updateProgress(100, '初始化成功！') 
      // 设置启动状态
      localStorage.setItem('appStarted', 'true')
      
      // 跳转到欢迎页，使用第一个实例的昵称
      setTimeout(() => {
        router.push({
          name: 'WelcomePage',
          params: {
            nickname: result.instances[0]?.nickname || '用户'
          }
        })
      }, 500)
      
    } else {
      if (result.code === 'ENV_NOT_CONFIGURED') {
        initializing.value = false
        showEnvConfigDialog.value = true
        return
      }
      throw new Error(result.message)
    }
    
  } catch (error) {
    progressStatus.value = 'exception'
    updateProgress(100, `启动失败: ${(error as Error).message}`)
    ElMessage.error(`启动失败: ${(error as Error).message}`)
    // 重置按钮状态
    initializing.value = false
  }
}

const startAutoConfig = async () => {
  try {
    if (autoConfigRunning.value) return
    autoConfigRunning.value = true
    autoConfigSteps.value = {1:'pending',2:'pending',3:'pending',4:'pending'}
    const res = await autoConfigWechat41()
    if (res.success) {
      showEnvConfigDialog.value = false
      showConfigCompleteDialog.value = true
    } else {
      ElMessage.error(res.message || '自动配置失败')
    }
  } catch (e) {
    ElMessage.error('自动配置失败')
  } finally {
    autoConfigRunning.value = false
  }
}

const launchAppAfterConfig = async () => {
  try {
    initializing.value = true
    updateProgress(20, '正在检查微信状态...')
    const result = await initializeMultipleWechat()
    if (result.success) {
      updateProgress(100, '初始化成功！')
      localStorage.setItem('appStarted', 'true')
      showConfigCompleteDialog.value = false
      setTimeout(() => {
        router.push({
          name: 'WelcomePage',
          params: { nickname: result.instances[0]?.nickname || '用户' }
        })
      }, 500)
      // stopNarrator()
    } else {
      ElMessage.error(result.message || '初始化失败')
    }
  } finally {
    initializing.value = false
  }
}

function goAgentLogin() {
  if (agentName.value) {
    router.push({ path: '/agent/login', query: { agent: agentName.value } })
  } else {
    router.push('/agent/login')
  }
}
</script>
  
