interface SvgConfig {
    [key: string]: {
      path: string
      fallback?: string
    }
  }
  
  interface LoadStatus {
    [key: string]: 'loading' | 'loaded' | 'error'
  }
  
  class SvgLoader {
    private static instance: SvgLoader
    private loadStatus: LoadStatus = {}
    private preloadedImages: Record<string, HTMLImageElement> = {}
    private config: SvgConfig = {}
    private globalFallback = '/icon/empty.svg'
    private retryCount: Record<string, number> = {}
    private maxRetries = 2
  
    // eslint-disable-next-line @typescript-eslint/no-empty-function
    private constructor() {}
  
    static getInstance(): SvgLoader {
      if (!SvgLoader.instance) {
        SvgLoader.instance = new SvgLoader()
      }
      return SvgLoader.instance
    }
  
    // 注册SVG配置
    registerConfig(config: SvgConfig): void {
      this.config = { ...this.config, ...config }
    }
  
    // 设置全局备用图片
    setGlobalFallback(path: string): void {
      this.globalFallback = path
    }
  
      // 获取图片路径
    getPath(iconName: string): string {
      const iconConfig = this.config[iconName]
      if (!iconConfig) {
        console.warn(`未找到图标配置: ${iconName}，请确保已注册配置`)
        return this.globalFallback
      }

      const status = this.loadStatus[iconName]
      if (status === 'error') {
        return iconConfig.fallback || this.globalFallback
      }

      return iconConfig.path
    }
  
    // 处理图片加载成功
    handleLoad(event: Event): void {
      const img = event.target as HTMLImageElement
      const iconName = this.getIconNameFromSrc(img.src)
      if (iconName) {
        this.loadStatus[iconName] = 'loaded'
        this.preloadedImages[iconName] = img
        // console.debug(`SVG加载成功: ${iconName}`)
      }
    }
  
    // 处理图片加载失败
    handleError(event: Event): void {
      const img = event.target as HTMLImageElement
      const iconName = this.getIconNameFromSrc(img.src)
      
      if (!iconName) return
  
      const currentRetries = this.retryCount[iconName] || 0
      const iconConfig = this.config[iconName]
      
      // 防止无限重试
      if (currentRetries >= this.maxRetries) {
        console.warn(`SVG加载失败达到最大重试次数: ${iconName}`)
        this.loadStatus[iconName] = 'error'
        return
      }
  
      this.retryCount[iconName] = currentRetries + 1
      this.loadStatus[iconName] = 'error'
      
      // 尝试备用路径
      const fallbackPath = iconConfig?.fallback || this.globalFallback
      if (img.src !== fallbackPath) {
        console.warn(`SVG加载失败: ${iconName}, 尝试备用路径 (重试 ${currentRetries + 1}/${this.maxRetries})`)
        img.src = fallbackPath
      }
    }
  
    // 从src提取图标名称
    private getIconNameFromSrc(src: string): string | null {
      for (const [name, config] of Object.entries(this.config)) {
        const fileName = config.path.split('/').pop()
        if (fileName && src.endsWith(fileName)) {
          return name
        }
      }
      return null
    }
  
    // 预加载图片
    async preloadImages(iconNames?: string[]): Promise<void> {
      const namesToLoad = iconNames || Object.keys(this.config)
      
      const promises = namesToLoad.map(name => {
        return new Promise<void>((resolve) => {
          const config = this.config[name]
          if (!config) {
            resolve()
            return
          }
    
          const img = new Image()
          this.loadStatus[name] = 'loading'
          
          img.onload = () => {
            this.loadStatus[name] = 'loaded'
            this.preloadedImages[name] = img
            // console.debug(`SVG预加载成功: ${name}`)
            resolve()
          }
          
          img.onerror = () => {
            this.loadStatus[name] = 'error'
            console.warn(`SVG预加载失败: ${name}`)
            resolve()
          }
          
          // 直接使用配置的路径，不使用require
          img.src = config.path
        })
      })
      
      await Promise.all(promises)
      console.debug('SVG预加载完成')
    }
  
    // 检查图片可用性
    async checkAvailability(iconName: string): Promise<boolean> {
      const config = this.config[iconName]
      if (!config) return false
  
      return new Promise((resolve) => {
        const img = new Image()
        img.onload = () => resolve(true)
        img.onerror = () => resolve(false)
        img.src = config.path
      })
    }
  
    // 获取加载状态
    getLoadStatus(iconName: string): 'loading' | 'loaded' | 'error' | 'unknown' {
      return this.loadStatus[iconName] || 'unknown'
    }
  
    // 重置重试计数
    resetRetryCount(iconName?: string): void {
      if (iconName) {
        delete this.retryCount[iconName]
      } else {
        this.retryCount = {}
      }
    }
  }
  
  export default SvgLoader